import{_ as o,W as l,X as t,Y as i,$ as n,a0 as e,a1 as s,Z as c,D as r}from"./framework-805da640.js";const p={},d=n("h1",{id:"简介",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#简介","aria-hidden":"true"},"#"),e(" 简介")],-1),u=n("p",null,[e("环境变量存储操作系统和其他程序使用的数据。 例如， "),n("code",null,"WINDIR"),e(" 环境变量包含 Windows 安装目录的位置。 程序可以查询此变量的值，以确定 Windows 操作系统文件所在的位置。")],-1),h=n("p",null,"PowerShell 可以访问和管理任何受支持的操作系统平台中的环境变量。 借助 PowerShell 环境提供程序，可以在当前控制台中获取、添加、更改、清除和删除环境变量。",-1),v=c(`<h1 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h1><p>涉及到三个参数：</p><ul><li><code>env_name</code>: 环境变量名称</li><li><code>env_value</code>: 环境变量的值，始终存储为字符串，不能为空</li><li><code>env_scope</code>: 环境变量的范围</li></ul><p>在 Windows 上，可以在三个范围内定义环境变量：</p><ul><li>计算机 (或系统) 范围：<code>Machine</code></li><li>用户范围: <code>User</code></li><li>进程范围: 包含当前进程或 PowerShell 会话中可用的环境变量。 此变量列表继承自父进程，是从计算机和用户范围内的变量构造的</li></ul><p>:::warning{title=&quot;注意：<code>System.Environment</code>方法才能永久更改环境变量&quot;} 在 PowerShell 中更改环境变量时，更改仅影响当前会话。 此行为类似于 Windows Command Shell 中命令的行为 <code>Set</code> 和基于 UNIX 的环境中的 <code>Setenv</code> 命令的行为。 若要更改<code>Machine</code> 或 <code>User</code> 作用域中的值，必须使用 <code>System.Environment</code> 类的方法。<br> 若要对计算机范围(<code>Machine</code>)的变量进行更改，还必须具有管理员权限。 :::</p><h2 id="设置和修改环境变量" tabindex="-1"><a class="header-anchor" href="#设置和修改环境变量" aria-hidden="true">#</a> 设置和修改环境变量</h2><p>语法：</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token namespace">[Environment]</span>::SetEnvironmentVariable<span class="token punctuation">(</span>env_name<span class="token punctuation">,</span> env_value<span class="token punctuation">,</span> env_scope<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>示例：</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token comment"># 设置JAVA_HOME环境变量</span>
<span class="token namespace">[Environment]</span>::SetEnvironmentVariable<span class="token punctuation">(</span><span class="token string">&#39;JAVA_HOME&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;C:\\Program Files\\Java\\jdk-11.0.13&#39;</span> <span class="token punctuation">,</span> <span class="token string">&#39;Machine&#39;</span><span class="token punctuation">)</span>

<span class="token comment"># 设置PATH环境变量</span>
<span class="token namespace">[Environment]</span>::SetEnvironmentVariable<span class="token punctuation">(</span><span class="token string">&quot;PATH&quot;</span><span class="token punctuation">,</span> <span class="token variable">$env</span>:PATH <span class="token operator">+</span> <span class="token string">&quot;;C:\\Program Files\\Go\\bin\\&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Machine&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="查询环境变量" tabindex="-1"><a class="header-anchor" href="#查询环境变量" aria-hidden="true">#</a> 查询环境变量</h2><p>语法：</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token comment"># 方法一：</span>
<span class="token variable">$Env</span>:&lt;env_name&gt;

<span class="token comment"># 方法二：</span>
<span class="token namespace">[Environment]</span>::GetEnvironmentVariable<span class="token punctuation">(</span>env_name<span class="token punctuation">,</span> env_scope<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="删除环境变量" tabindex="-1"><a class="header-anchor" href="#删除环境变量" aria-hidden="true">#</a> 删除环境变量</h2><p>语法：</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token namespace">[Environment]</span>::SetEnvironmentVariable<span class="token punctuation">(</span>env_name<span class="token punctuation">,</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span> env_scope<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>示例：</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token namespace">[Environment]</span>::SetEnvironmentVariable<span class="token punctuation">(</span><span class="token string">&#39;Foo&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;Machine&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h1 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h1>`,20),m={href:"https://zhuanlan.zhihu.com/p/424377493",target:"_blank",rel:"noopener noreferrer"},k={href:"https://learn.microsoft.com/zh-cn/powershell/module/microsoft.powershell.core/about/about_environment_variables?view=powershell-7.2",target:"_blank",rel:"noopener noreferrer"};function _(b,g){const a=r("ExternalLinkIcon");return l(),t("div",null,[d,u,h,i(" more "),v,n("ol",null,[n("li",null,[n("a",m,[e("使用 PowerShell 永久修改环境变量"),s(a)])]),n("li",null,[n("a",k,[e(" about_Environment_Variables"),s(a)])])])])}const E=o(p,[["render",_],["__file","Powershell永久修改环境变量.html.vue"]]);export{E as default};
